tomationEvent(AutomationEvents.SelectionPatternOnInvalidated);        }    }    private void ResolveScrollViewerOnLayoutUpdated(object? sender, EventArgs e)    {        this.LayoutUpdated -= this.ResolveScrollViewerOnLayoutUpdated;        if (this.ScrollViewer != null)        {            this.ScrollViewer.GotFocus -= this.ScrollViewer_GotFocus;            this.ScrollViewer.RemoveHandler(UIElement.MouseLeftButtonDownEvent, new MouseButtonEventHandler(ScrollViewer_MouseLeftButtonDown));            this.ScrollViewer.RemoveHandler(UIElement.MouseLeftButtonUpEvent, new MouseButtonEventHandler(ScrollViewer_MouseLeftButtonUp));            this.ScrollViewer.RemoveHandler(UIElement.MouseWheelEvent, new MouseWheelEventHandler(ScrollViewer_MouseWheel));            this.ScrollViewer.SizeChanged -= this.ScrollViewer_SizeChanged;            this.ScrollViewer.ScrollChanged -= this.ScrollViewer_ScrollChanged;        }        this.ScrollViewer = GetTemplateChild("ScrollViewerElement") as ScrollViewer;        if (this.ScrollViewer != null)        {            this.ScrollViewer.GotFocus += this.ScrollViewer_GotFocus;            this.ScrollViewer.AddHandler(UIElement.MouseLeftButtonDownEvent, new MouseButtonEventHandler(ScrollViewer_MouseLeftButtonDown), handledEventsToo: true);            this.ScrollViewer.AddHandler(UIElement.MouseLeftButtonUpEvent, new MouseButtonEventHandler(ScrollViewer_MouseLeftButtonUp), handledEventsToo: true);            this.ScrollViewer.AddHandler(UIElement.MouseWheelEvent, new MouseWheelEventHandler(ScrollViewer_MouseWheel), handledEventsToo: true);            this.ScrollViewer.SizeChanged += this.ScrollViewer_SizeChanged;            this.ScrollViewer.ScrollChanged += this.ScrollViewer_ScrollChanged;            this.UnBindScrollVisibility();            this.UpdateScrollButtonsState();            this.UpdateScrollButtonsVisibility();            this.BindScrollVisibility();            this.SetTabStripTabNavigationMode(KeyboardNavigationMode.Once);            this.ScrollTabStripToStartBound();        }    }    private void UpdateScrollButtonsVisibility()    {        if (this.LeftScrollButton != null)        {            this.LeftScrollButton.Visibility = (Visibility)GetValue(CalculatedScrollvisibilityProperty);        }        if (this.RightScrollButton != null)        {            this.RightScrollButton.Visibility = (Visibility)GetValue(CalculatedScrollvisibilityProperty);        }    }    private void UnBindScrollVisibility()    {        this.ClearValue(CalculatedScrollvisibilityProperty);    }    private void BindScrollVisibility()    {        if (this.ScrollViewer != null)        {            Binding binding = new Binding();            binding.Source = this.ScrollViewer;            binding.Path = new PropertyPath(ScrollViewer.ComputedHorizontalScrollBarVisibilityProperty);            binding.Mode = BindingMode.OneWay;            this.SetBinding(CalculatedScrollvisibilityProperty, binding);        }    }    public void ScrollIntoView(object item)    {        int num = this.Items.IndexOf(item);        if (num != -1 &&            this.ScrollViewer != null &&            this.ItemContainerGenerator.ContainerFromIndex(num) is FrameworkElement container)        {            var viewportRelation = CalculateContainerDirectionalVisibility(container);            if (viewportRelation != ViewportRelation.InView)            {                this.BringContainerIntoView(container, viewportRelation);            }        }    }    /// <inheritdoc/>    internal override void BringSelectedItemIntoView()    {        if (isPinStateChangingOfUnselectedTab)        {            return;        }        Action bringIntoView = new Action(() =>        {            ScrollIntoView(this.SelectedItem);        });        if (this.SelectedIndex != -1)        {            this.Dispatcher.BeginInvoke(() =>            {                this.Dispatcher.BeginInvoke(bringIntoView, DispatcherPriority.Loaded);            });        }    }    protected virtual void OnLeftScrollButtonClick(object sender, RoutedEventArgs e)    {        if (this.ScrollViewer != null)        {            if (this.ScrollMode == TabControlScrollMode.Pixel)            {                this.AdjustScrollBarOffset(-16.0);            }            else if (this.ScrollMode == TabControlScrollMode.Item)            {                this.ScrollOneItemBack();            }            else            {                this.ScrollOneViewportBack();            }        }    }    protected virtual void OnRightScrollButtonClick(object sender, RoutedEventArgs e)    {        if (this.ScrollViewer != null)        {            if (this.ScrollMode == TabControlScrollMode.Pixel)            {                this.AdjustScrollBarOffset(16.0);            }            else if (this.ScrollMode == TabControlScrollMode.Item)            {                ScrollOneItemForward();            }            else            {                ScrollOneViewportForward();            }        }    }    private void ScrollTabStripToStartBound()    {        if (ScrollViewer != null && (TabStripPlacement == Dock.Left || TabStripPlacement == Dock.Bottom))        {            Action scroll = delegate            {                ScrollViewer.ScrollToHorizontalOffset(2147483647.0);            };            base.Dispatcher.BeginInvoke((Action)delegate            {                base.Dispatcher.BeginInvoke(scroll, DispatcherPriority.SystemIdle);            });        }    }    private void UpdateScrollButtonsState()    {        if (LeftScrollButton != null)        {            LeftScrollButton.IsEnabled = CanScrollBack();        }        if (RightScrollButton != null)        {            RightScrollButton.IsEnabled = CanScrollForward();        }    }    private void ScrollViewer_MouseWheel(object sender, MouseWheelEventArgs e)    {        FrameworkElement frameworkElement = FocusManagerHelper.GetFocusedElement(this) as FrameworkElement;        if (base.IsFocused || (base.TabStrip != null && frameworkElement != null && base.TabStrip.IsAncestorOf(frameworkElement)))        {            if (e.Delta < 0)            {                e.Handled = CanScrollBack();                ScrollOneItemBack();            }            if (e.Delta > 0)            {                e.Handled = CanScrollForward();                ScrollOneItemForward();            }        }    }    private void BringContainerIntoView(FrameworkElement container, ViewportRelation currentRelativePosition)    {        if (base.TabStrip == null)        {            return;        }        double num = 0.0;        if (IsPanelHorizontal)        {            double num2 = 0.0;            try            {                num2 = container.TransformToVisual(base.TabStrip).Transform(default(Point)).X;            }            catch (ArgumentException)            {            }            double num3 = num2 + container.ActualWidth;            num = ((currentRelativePosition != ViewportRelation.BeforeViewport) ? (num3 - ScrollViewer.HorizontalOffset - ScrollViewer.ViewportWidth + base.TabStrip.Margin.Left + base.TabStrip.Margin.Right) : (num2 - ScrollViewer.HorizontalOffset + base.TabStrip.Margin.Left + base.TabStrip.Margin.Right));        }        else        {            double num4 = 0.0;            try            {                num4 = container.TransformToVisual(base.TabStrip).Transform(default(Point)).Y;            }            catch (ArgumentException)            {            }            double num5 = num4 + container.ActualHeight;            num = ((currentRelativePosition != ViewportRelation.BeforeViewport) ? (num5 - ScrollViewer.VerticalOffset - ScrollViewer.ViewportHeight + base.TabStrip.Margin.Top + base.TabStrip.Margin.Bottom) : (num4 - ScrollViewer.VerticalOffset + base.TabStrip.Margin.Top + base.TabStrip.Margin.Bottom));        }        AdjustScrollBarOffset(num);    }    private void AdjustScrollBarOffset(double adjustment)    {        if (adjustment > 0.0)        {            adjustment = CoerceScrollForward(adjustment);        }        if (adjustment < 0.0)        {            adjustment = 0.0 - CoerceScrollBack(0.0 - adjustment);        }        if (IsPanelHorizontal)        {            ScrollViewer.ScrollToHorizontalOffset(adjustment + ScrollViewer.HorizontalOffset);            double num = 0.0;            if (base.TabStrip.RenderTransform != null)            {                num = base.TabStrip.RenderTransform.Transform(default(Point)).X;            }            adjustment += num;            if (!RadDragAndDropManager.IsDragging)            {                AnimationExtensions.Create().Animate(base.TabStrip).EnsureDefaultTransforms()                    .MoveX(0.0, adjustment, 0.5, 0.0)                    .Easings(Easings.SlideUp1)                    .AdjustSpeed()                    .OnComplete(UpdateScrollButtonsState)                    .PlayIfPossible(this);            }        }        else        {            this.ScrollViewer.ScrollToVerticalOffset(adjustment + ScrollViewer.VerticalOffset);            double num2 = 0.0;            if (this.TabStrip.RenderTransform != null)            {                num2 = this.TabStrip.RenderTransform.Transform(default(Point)).Y;            }            adjustment += num2;            if (!RadDragAndDropManager.IsDragging)            {                AnimationExtensions.Create().Animate(this.TabStrip).EnsureDefaultTransforms()                    .MoveY(0.0, adjustment, 0.5, 0.0)                    .Easings(Easings.SlideUp1)                    .AdjustSpeed()                    .OnComplete(UpdateScrollButtonsState)                    .PlayIfPossible(this);            }        }        this.Dispatcher.BeginInvoke(            UpdateScrollButtonsState,            DispatcherPriority.ApplicationIdle);    }    private void ScrollOneViewportBack()    {        if (this.HasItems && ScrollViewer != null)        {            if (IsPanelHorizontal)            {                AdjustScrollBarOffset(0.0 - ScrollViewer.ViewportWidth);            }            else            {                AdjustScrollBarOffset(0.0 - ScrollViewer.ViewportHeight);            }        }    }    private void ScrollOneItemBack()    {        if (!this.HasItems || this.ScrollViewer == null || this.TabStrip == null)        {            return;        }        IEnumerable<ITabItem> containersInCorrectOrder = GetContainersInCorrectOrder(false);        ITabItem? tabItem = null;        if (IsPanelHorizontal)        {            tabItem = containersInCorrectOrder.SkipWhile(item =>            {                double num = 0.0;                try                {                    num = item.Control.TransformToVisual(this.TabStrip).Transform(default(Point)).X;                }                catch (ArgumentException)                {                }                return num >= ScrollViewer.HorizontalOffset;            }).FirstOrDefault();        }        else        {            tabItem = containersInCorrectOrder.SkipWhile(item =>            {                double num = 0.0;                try                {                    num = item.Control.TransformToVisual(this.TabStrip).Transform(default(Point)).Y;                }                catch (ArgumentException)                {                }                return num >= ScrollViewer.VerticalOffset;            }).FirstOrDefault();        }        if (tabItem != null)        {            BringContainerIntoView(tabItem.Control, ViewportRelation.BeforeViewport);        }    }    private void ScrollOneViewportForward()    {        if (this.HasItems && ScrollViewer != null)        {            if (IsPanelHorizontal)            {                AdjustScrollBarOffset(ScrollViewer.ViewportWidth);            }            else            {                AdjustScrollBarOffset(ScrollViewer.ViewportHeight);            }        }    }    private void ScrollOneItemForward()    {        if (!this.HasItems || this.ScrollViewer == null || this.TabStrip == null)        {            return;        }        ITabItem? radTabItem = null;        var containersInCorrectOrder = GetContainersInCorrectOrder(scrollingForward: true);        radTabItem = !this.IsPanelHorizontal ?            containersInCorrectOrder.SkipWhile(item =>            {                double num = 0.0;                try                {                    num = item.Control.TransformToVisual(this.TabStrip).Transform(default(Point)).Y;                }                catch (ArgumentException)                {                }                return (num + item.Control.ActualHeight + this.TabStrip.Margin.Top + this.TabStrip.Margin.Bottom - this.ScrollViewer.VerticalOffset - this.ScrollViewer.ViewportHeight) < 6.0;            }).FirstOrDefault() :            containersInCorrectOrder.SkipWhile(item =>            {                double num = 0.0;                try                {                    num = item.Control.TransformToVisual(this.TabStrip).Transform(default(Point)).X;                }                catch (ArgumentException)                {                }                return (num + item.Control.ActualWidth + this.TabStrip.Margin.Left + this.TabStrip.Margin.Right - this.ScrollViewer.HorizontalOffset - this.ScrollViewer.ViewportWidth) < 6.0;            }).FirstOrDefault();        if (radTabItem != null)        {            this.BringContainerIntoView(radTabItem.Control, ViewportRelation.AfterViewport);        }    }    private IEnumerable<ITabItem> GetContainersInCorrectOrder(bool scrollingForward)    {        if ((scrollingForward || (TabStripPlacement != Dock.Top && TabStripPlacement != Dock.Right)) && (!scrollingForward || (TabStripPlacement != Dock.Left && TabStripPlacement != Dock.Bottom)))        {            return this.GetContainers<ITabItem>();        }        return this.GetContainers<ITabItem>().Reverse();    }    private double CoerceScrollForward(double desiredScroll)    {        if (this.ScrollViewer != null && this.TabStrip != null)        {            if (this.IsPanelHorizontal)            {                return Math.Max(                    Math.Min(                    this.TabStrip.ActualWidth + this.TabStrip.Margin.Left + this.TabStrip.Margin.Right - this.ScrollViewer.HorizontalOffset - ScrollViewer.ViewportWidth,                    desiredScroll),                    0.0);            }            return Math.Max(                Math.Min(                    this.TabStrip.ActualHeight + this.TabStrip.Margin.Top + this.TabStrip.Margin.Bottom - this.ScrollViewer.VerticalOffset - ScrollViewer.ViewportHeight,                    desiredScroll), 0.0);        }        return desiredScroll;    }    private double CoerceScrollBack(double desiredScroll)    {        if (ScrollViewer != null)        {            if (IsPanelHorizontal)            {                return Math.Max(0.0, Math.Min(ScrollViewer.HorizontalOffset, desiredScroll));            }            return Math.Max(0.0, Math.Min(ScrollViewer.VerticalOffset, desiredScroll));        }        return desiredScroll;    }    private bool CanScrollForward()    {        double value = 0.0;        if (this.ScrollViewer != null && this.TabStrip != null)        {            if (this.IsPanelHorizontal)            {                value = this.ScrollViewer.HorizontalOffset + this.ScrollViewer.ViewportWidth - this.TabStrip.ActualWidth - this.TabStrip.Margin.Left - this.TabStrip.Margin.Right;            }            else            {                value = this.ScrollViewer.VerticalOffset + this.ScrollViewer.ViewportHeight - this.TabStrip.ActualHeight - this.TabStrip.Margin.Top - this.TabStrip.Margin.Bottom;            }        }        return value != 0.0;    }    private bool CanScrollBack()    {        if (this.ScrollViewer != null)        {            if (this.IsPanelHorizontal)            {                return this.ScrollViewer.HorizontalOffset > 0.0;            }            return this.ScrollViewer.VerticalOffset > 0.0;        }        return false;    }    private ViewportRelation CalculateContainerDirectionalVisibility(FrameworkElement container)    {        if (this.IsPanelHorizontal)        {            return this.CalculateContainerHorizontalVisibility(container);        }        return this.CalculateContainerVerticalVisibility(container);    }    private ViewportRelation CalculateContainerHorizontalVisibility(FrameworkElement container)    {        if (this.ScrollViewer == null || this.ScrollViewer.ComputedHorizontalScrollBarVisibility == Visibility.Collapsed)        {            return ViewportRelation.InView;        }        if (this.TabStrip != null)        {            double num = 0.0;            try            {                num = container.TransformToVisual(this.TabStrip).Transform(default(Point)).X;            }            catch (ArgumentException)            {            }            double num2 = num + container.ActualWidth;            if (num - this.ScrollViewer.HorizontalOffset < 0.0)            {                return ViewportRelation.BeforeViewport;            }            if (num2 - this.ScrollViewer.HorizontalOffset > this.ScrollViewer.ViewportWidth)            {                return ViewportRelation.AfterViewport;            }        }        return ViewportRelation.InView;    }    private ViewportRelation CalculateContainerVerticalVisibility(FrameworkElement container)    {        if (this.ScrollViewer == null || this.ScrollViewer.ComputedVerticalScrollBarVisibility == Visibility.Collapsed)        {            return ViewportRelation.InView;        }        if (this.TabStrip != null)        {            double num = 0.0;            try            {                num = container.TransformToVisual(this.TabStrip).Transform(default(Point)).Y;            }            catch (ArgumentException)            {            }            double num2 = num + container.ActualHeight;            if ((num - this.ScrollViewer.VerticalOffset) < 0.0)            {                return ViewportRelation.BeforeViewport;            }            if ((num2 - this.ScrollViewer.VerticalOffset) > this.ScrollViewer.ViewportHeight)            {                return ViewportRelation.AfterViewport;            }        }        return ViewportRelation.InView;    }}